const items = $input.all();

if (!items || items.length === 0) {
  return [{ json: { enviar: false, message: null } }];
}

// ── 1. Gatilho: existe algum cert nos marcos exatos? ──────────────────────────
const MARCOS = new Set([15, 10, 5, 1]);

const gatilhoDisparou = items.some(({ json: r }) => {
  if (r.daysLeft === null || r.daysLeft === undefined) return false;
  if (r.daysLeft <= 0) return true;          // vencido
  return MARCOS.has(r.daysLeft);             // exatamente 15, 10, 5 ou 1
});

if (!gatilhoDisparou) {
  return [{ json: { enviar: false, message: null } }];
}

// ── 2. Conteúdo: todos em zona de alerta (daysLeft ≤ 15 ou vencido) ───────────
const emAlerta = items
  .map(i => i.json)
  .filter(r => r.daysLeft !== null && r.daysLeft !== undefined && r.daysLeft <= 15)
  .sort((a, b) => a.daysLeft - b.daysLeft);  // mais urgente primeiro

// ── 3. Emoji por severidade ───────────────────────────────────────────────────
function getEmoji(r) {
  if (r.mismatch)      return '🔀';
  if (r.daysLeft <= 0) return '🔴';
  if (r.daysLeft <= 5) return '🚨';
  if (r.daysLeft <= 10) return '⚠️';
  return '📅';
}

// ── 4. Resumo por categoria ───────────────────────────────────────────────────
const c = (fn) => emAlerta.filter(fn).length;
const resumo = [
  c(r => r.mismatch) > 0                                      ? `🔀 Mismatch: ${c(r => r.mismatch)}` : null,
  c(r => !r.mismatch && r.daysLeft <= 0) > 0                  ? `🔴 Vencidos: ${c(r => !r.mismatch && r.daysLeft <= 0)}` : null,
  c(r => !r.mismatch && r.daysLeft > 0 && r.daysLeft <= 5) > 0  ? `🚨 Críticos ≤5d: ${c(r => !r.mismatch && r.daysLeft > 0 && r.daysLeft <= 5)}` : null,
  c(r => !r.mismatch && r.daysLeft > 5 && r.daysLeft <= 10) > 0 ? `⚠️ Atenção ≤10d: ${c(r => !r.mismatch && r.daysLeft > 5 && r.daysLeft <= 10)}` : null,
  c(r => !r.mismatch && r.daysLeft > 10 && r.daysLeft <= 15) > 0 ? `📅 Aviso ≤15d: ${c(r => !r.mismatch && r.daysLeft > 10 && r.daysLeft <= 15)}` : null,
].filter(Boolean).join(' | ');

// ── 5. Linhas por domínio ─────────────────────────────────────────────────────
const now = new Date().toLocaleString('pt-BR', { timeZone: 'America/Sao_Paulo' });

const linhas = emAlerta.map(r => {
  const portaLabel  = r.port !== 443 ? ` ⚡ porta ${r.port}` : ' (443)';
  const diasStr     = r.daysLeft <= 0
    ? `vencido há ${Math.abs(r.daysLeft)} dia(s)`
    : `${r.daysLeft} dia(s)`;
  const mismatchStr = r.mismatch
    ? `\n   ⚠️ *Mismatch: cert NÃO cobre este domínio!*\n   Cert CN : ${r.certCN || '—'}`
    : '';

  return (
    `${getEmoji(r)} *${r.hostname}*${portaLabel}\n` +
    `   Status  : ${r.status}\n` +
    `   Validade: ${r.validTo ?? '—'}\n` +
    `   Faltam  : ${diasStr}` +
    mismatchStr
  );
});

// ── 6. Monta mensagem final ───────────────────────────────────────────────────
const message =
  `🔐 *Alerta SSL*\n` +
  `🕐 ${now}\n` +
  `📋 ${emAlerta.length} domínio(s) em alerta\n` +
  `${resumo}\n` +
  `${'─'.repeat(32)}\n\n` +
  linhas.join('\n\n');

return [{ json: { enviar: true, message } }];

const tls = require('tls');
const items = $input.all();

if (!items || items.length === 0) {
  return [{ json: { message: '⚠️ Nenhum domínio encontrado na planilha.' } }];
}

function getPort(row) {
  const key = Object.keys(row).find(k => k.toLowerCase() === 'porta');
  const raw = key ? row[key] : undefined;
  const parsed = parseInt(raw);
  return (raw !== undefined && raw !== null && raw !== '' && !isNaN(parsed) && parsed > 0 && parsed <= 65535)
    ? parsed
    : 443;
}

function isIP(host) {
  return /^(\d{1,3}\.){3}\d{1,3}$/.test(host) || host.includes(':');
}

function checkSSL(rawHostname, port) {
  return new Promise((resolve) => {
    const hostname = String(rawHostname).replace(/^https?:\/\//i, '').split('/')[0].trim();
    const hostIsIP = isIP(hostname);
    const options  = { host: hostname, port, rejectUnauthorized: false, ...(hostIsIP ? {} : { servername: hostname }) };
    let settled = false;
    const done = (result) => { if (!settled) { settled = true; resolve({ hostname, port, ...result }); } };

    try {
      const socket = tls.connect(options, () => {
        try {
          const cert = socket.getPeerCertificate(true);
          socket.destroy();

          if (!cert || !cert.valid_to) {
            return done({ status: 'Sem certificado', validTo: null, daysLeft: null, certCN: null, certSANs: null, mismatch: false });
          }

          const validTo  = new Date(cert.valid_to);
          const now      = new Date();
          const daysLeft = Math.floor((validTo - now) / (1000 * 60 * 60 * 24));
          const certCN   = cert.subject?.CN || null;
          const certSANs = cert.subjectaltname
            ? cert.subjectaltname.split(',').map(s => s.trim().replace(/^DNS:/i, '')).filter(s => s && !s.startsWith('IP:'))
            : [];

          let mismatch = false;
          if (!hostIsIP) {
            function covers(host, pattern) {
              if (pattern.startsWith('*.')) {
                const base = pattern.slice(2);
                return host !== base && host.endsWith('.' + base) && host.split('.').length === base.split('.').length + 1;
              }
              return host === pattern;
            }
            const allNames = [...new Set([certCN, ...certSANs].filter(Boolean))];
            mismatch = allNames.length > 0 && !allNames.some(n => covers(hostname, n));
          }

          done({
            status  : daysLeft <= 0 ? 'Expirado' : 'Válido',
            validTo : validTo.toLocaleDateString('pt-BR'),
            daysLeft,
            certCN,
            certSANs: certSANs.length > 0 ? certSANs : null,
            mismatch,
          });
        } catch (err) {
          socket.destroy();
          done({ status: `Erro leitura: ${err.message}`, validTo: null, daysLeft: null, certCN: null, certSANs: null, mismatch: false });
        }
      });

      socket.setTimeout(10000, () => { socket.destroy(); done({ status: 'Timeout',            validTo: null, daysLeft: null, certCN: null, certSANs: null, mismatch: false }); });
      socket.on('error', (err)   => {                   done({ status: `Erro: ${err.message}`, validTo: null, daysLeft: null, certCN: null, certSANs: null, mismatch: false }); });
    } catch (err) {
      done({ status: `Erro: ${err.message}`, validTo: null, daysLeft: null, certCN: null, certSANs: null, mismatch: false });
    }
  });
}

const resultados = await Promise.all(
  items
    .filter(i => {
      const key = Object.keys(i.json).find(k => k.toLowerCase() === 'domínio' || k.toLowerCase() === 'dominio');
      return key && i.json[key];
    })
    .map(i => {
      const key = Object.keys(i.json).find(k => k.toLowerCase() === 'domínio' || k.toLowerCase() === 'dominio');
      const port = getPort(i.json);
      return checkSSL(i.json[key], port);
    })
);

// Cada resultado vira um item separado no n8n — ideal para filtrar no próximo nó
return resultados.map(r => ({ json: r }));
